mapper.select:
SELECT c.id, c.name, c.slug, c.icon, c.description, c.level, c.parent_id AS parentId, p.name AS parentName, c.article_count AS articleCount, c.is_recommend AS isRecommend, c.is_nav AS isNav, c.status, c.sort, c.created_at AS createdAt, c.updated_at AS updatedAt,
/* 直接子分类数量 */ (SELECT COUNT(*) FROM category sub WHERE sub.parent_id = c.id) AS childCount,
/* 今日（0点到当前）该分类下发布的文章数 */ (SELECT COUNT(*) FROM article a WHERE a.category_id = c.id AND a.status = '1' AND a.published_at >= CURDATE() AND a.published_at < DATE_ADD(CURDATE(), INTERVAL 1 DAY) ) AS todayArticleCount,
/* 昨日该分类下发布的文章数 */ (SELECT COUNT(*) FROM article a WHERE a.category_id = c.id AND a.status = '1' AND a.published_at >= DATE_SUB(CURDATE(), INTERVAL 1 DAY) AND a.published_at < CURDATE() ) AS yesterdayArticleCount
FROM category c LEFT JOIN category p ON c.parent_id = p.id AND c.parent_id != 0
AND c.name LIKE CONCAT('%', #{req.name}, '%')
AND c.status = #{req.status}
AND c.level = #{req.level}
ORDER BY c.level ASC, c.sort ASC, c.id ASC LIMIT #{req.pageSize} OFFSET #{offset}

SELECT COUNT(*)
FROM category c


        AND c.name LIKE CONCAT('%', #{req.name}, '%')


        AND c.status = #{req.status}


        AND c.level = #{req.level}
